/**
 * NextAuth Type Extensions
 * Backend Lead Agent - Phase 1
 *
 * Extends NextAuth types to include custom fields in session and JWT
 */

import 'next-auth';
import 'next-auth/jwt';

declare module 'next-auth' {
  interface Session {
    user: {
      id: string;
      email: string;
      name?: string | null;
      image?: string | null;
    };
  }

  interface User {
    id: string;
    email: string;
    name?: string | null;
    image?: string | null;
  }
}

declare module 'next-auth/jwt' {
  interface JWT {
    userId?: string;
  }
}
